const input = $input.first().json || {};
if (input.relay?.validated_by_api === true) {
  return $input.all();
}
const crypto = require('crypto');
const body = JSON.stringify(input.body || input);
const sig = input.headers?.['x-hub-signature-256'] || '';
const expected = 'sha256=' + crypto.createHmac('sha256', $env.META_APP_SECRET).update(body).digest('hex');
if (sig !== expected) { throw new Error('Invalid webhook signature'); }
return $input.all();

const body = $input.first().json.body || $input.first().json;
const entry = body?.entry?.[0] || {};
const messaging = entry?.messaging?.[0] || null;
if (!messaging || messaging?.message?.is_echo) {
  return [{ json: { is_supported_event: false, is_status_update: true } }];
}
const attachments = messaging.message?.attachments || [];
const firstAttachmentType = String(attachments[0]?.type || '').toLowerCase();
const typeMap = { image: 'IMAGE', audio: 'AUDIO', video: 'VIDEO', file: 'FILE', sticker: 'STICKER' };
const mappedType = attachments.length > 0 ? (typeMap[firstAttachmentType] || 'UNKNOWN') : 'TEXT';
const text = messaging.message?.text || messaging.postback?.title || messaging.quick_reply?.payload || '';
return [{
  json: {
    is_supported_event: Boolean(messaging.message || messaging.postback),
    is_status_update: false,
    channel: 'INSTAGRAM',
    provider: 'META',
    provider_message_id: messaging.message?.mid || messaging.postback?.mid || null,
    provider_parent_message_id: messaging.message?.reply_to?.mid || null,
    external_user_id: messaging.sender?.id || null,
    channel_account_id: messaging.recipient?.id || $env.META_IG_REPLY_ENDPOINT_ID || null,
    external_display_name: messaging.sender?.name || '',
    message_type: mappedType,
    event_type: 'MESSAGE',
    direction: 'INBOUND',
    text_body: text,
    normalized_text: (text || '').trim(),
    media_url: attachments[0]?.payload?.url || null,
    raw_payload: messaging,
    received_at: new Date(messaging.timestamp || Date.now()).toISOString()
  }
}];

const gates = $input.first().json || {};
const lastInboundAt = gates.last_inbound_at ? new Date(gates.last_inbound_at).getTime() : Date.now();
const within24h = (Date.now() - lastInboundAt) <= (24 * 60 * 60 * 1000);
let blockedBy = null;
if (gates.is_opted_out) blockedBy = 'opt_out';
else if (gates.human_handoff) blockedBy = 'human_handoff';
else if (!within24h) blockedBy = 'outside_24h_window';
else if (Number(gates.consecutive_bot_outbound || 0) >= 3) blockedBy = 'too_many_bot_outbound';
return [{ json: { ...gates, can_reply: !blockedBy, blocked_by: blockedBy } }];

const playbook = $input.first().json || [];
const playbookArr = Array.isArray(playbook) ? playbook : [];
const sections = playbookArr.sort((a, b) => (a.priority || 0) - (b.priority || 0)).map(p => `### ${p.title}
${p.content}`).join('

');
const systemPrompt = `Sos NovaBot, asistente comercial de NovaVision para Instagram DM.

REGLAS ABSOLUTAS:
1. Responder siempre en español argentino, corto y claro.
2. No inventar precios ni promociones.
3. No insistir si el usuario pide frenar o hablar con humano.
4. No inventar rubro ni contexto que el lead no haya dicho.
5. Mantener mensajes aptos para DM, máximo 300 caracteres.

FORMATO JSON OBLIGATORIO:
{
  "reply": "texto",
  "engagement_delta": -10 a 20,
  "conversation_stage": "INTRO|DISCOVERY|FOLLOWUP|CLOSING|DEMO_OFFERED|DEMO_BOOKED",
  "intent": "interested|curious|objection|not_interested|spam|human_request",
  "should_notify_sales": true/false,
  "reasoning": "explicacion interna"
}

PLAYBOOK:
${sections || '(sin playbook)'}`;
return [{ json: { system_prompt: systemPrompt } }];

const history = $node['Load Conversation Context'].json || [];
const historyArr = Array.isArray(history) ? history : [];
const inbound = $node['Parse Instagram Event'].json;
const historyText = historyArr.reverse().map(h => `${h.direction}: ${h.message_text}`).join('\n');
return [{ json: {
  thread_id: $node['Append Inbound Event'].json.thread_id,
  contact_id: $node['Append Inbound Event'].json.contact_id,
  identity_id: $node['Append Inbound Event'].json.identity_id,
  lead_id: $node['Append Inbound Event'].json.lead_id,
  ai_engagement_score: Number($node['Append Inbound Event'].json.ai_engagement_score || 0),
  input_text: inbound.normalized_text,
  from_user_id: inbound.external_user_id,
  channel_account_id: inbound.channel_account_id,
  display_name: inbound.external_display_name || 'Instagram Lead',
  conversation_history: historyText
} }];

const raw = $input.first().json;
let aiOutput;
try {
  const content = raw.message?.content || raw.choices?.[0]?.message?.content || '';
  aiOutput = JSON.parse(content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
} catch (e) {
  aiOutput = { reply: 'Gracias por escribirnos. Un asesor te responde a la brevedad.', engagement_delta: 0, conversation_stage: 'INTRO', intent: 'human_request', should_notify_sales: true, reasoning: 'JSON parse failed' };
}
const prev = $node['Prepare AI Context'].json;
const validStages = ['INTRO', 'DISCOVERY', 'FOLLOWUP', 'CLOSING', 'DEMO_OFFERED', 'DEMO_BOOKED'];
const reply = String(aiOutput.reply || '').substring(0, 300);
const engagementDelta = Math.max(-10, Math.min(20, parseInt(aiOutput.engagement_delta) || 0));
const nextStage = validStages.includes(aiOutput.conversation_stage) ? aiOutput.conversation_stage : 'INTRO';
const newScore = Math.max(0, Math.min(100, Number(prev.ai_engagement_score || 0) + engagementDelta));
const isHot = newScore >= 80 || !!aiOutput.should_notify_sales;
return [{ json: {
  ...prev,
  reply,
  new_score: newScore,
  new_stage: nextStage,
  intent: aiOutput.intent || 'unknown',
  should_notify_sales: !!aiOutput.should_notify_sales,
  is_hot: isHot,
  reasoning: aiOutput.reasoning || ''
} }];

